CREATE TABLE IF NOT EXISTS meta(key TEXT PRIMARY KEY,value TEXT);
CREATE TABLE IF NOT EXISTS settings(id TEXT PRIMARY KEY,admin_fee INTEGER NOT NULL DEFAULT 10,game_fee INTEGER NOT NULL DEFAULT 100,split TEXT NOT NULL DEFAULT '[50,30,20]',api_league_id TEXT,api_season TEXT DEFAULT '2026');
CREATE TABLE IF NOT EXISTS users(id TEXT PRIMARY KEY,name TEXT NOT NULL,email TEXT NOT NULL UNIQUE,password_hash TEXT NOT NULL,role TEXT NOT NULL DEFAULT 'player',approved INTEGER NOT NULL DEFAULT 0,paid INTEGER NOT NULL DEFAULT 0,avatar TEXT,points INTEGER NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sessions(token TEXT PRIMARY KEY,user_id TEXT NOT NULL,created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS seasons(id TEXT PRIMARY KEY,name TEXT NOT NULL,description TEXT,sport TEXT NOT NULL,active INTEGER NOT NULL DEFAULT 0,public INTEGER NOT NULL DEFAULT 0,status TEXT NOT NULL DEFAULT 'draft');
CREATE TABLE IF NOT EXISTS matches(id TEXT PRIMARY KEY,season_id TEXT NOT NULL,external_id TEXT,phase TEXT,start_time TEXT,home TEXT,away TEXT,home_flag TEXT,away_flag TEXT,status TEXT NOT NULL DEFAULT 'locked',score TEXT,confirmed INTEGER NOT NULL DEFAULT 0,info TEXT);
CREATE UNIQUE INDEX IF NOT EXISTS idx_matches_external ON matches(external_id);
CREATE TABLE IF NOT EXISTS bets(user_id TEXT NOT NULL,match_id TEXT NOT NULL,pick TEXT NOT NULL,created_at TEXT,PRIMARY KEY(user_id,match_id));
CREATE TABLE IF NOT EXISTS proposals(id TEXT PRIMARY KEY,type TEXT NOT NULL,match_id TEXT,text TEXT NOT NULL,payload TEXT,state TEXT NOT NULL DEFAULT 'waiting',created_at TEXT);